// Local lightweight Shade shim for development — registers simple web components
// Uses <slot> for content projection so React children are always visible.
(function () {
    // --- Container-like elements: use Shadow DOM + <slot> ---
    // The slot projects React's light-DOM children into the shadow tree.
    function makeContainer(tagName, buildWrapper) {
        class C extends HTMLElement {
            constructor() {
                super();
                const root = this.attachShadow({ mode: 'open' });
                const wrapper = buildWrapper(this);
                const slot = document.createElement('slot');
                wrapper.appendChild(slot);
                root.appendChild(wrapper);
            }
        }
        customElements.define(tagName, C);
    }

    // shade-container
    makeContainer('shade-container', () => {
        const d = document.createElement('div');
        d.style.cssText = 'max-width:960px;margin:0 auto';
        return d;
    });

    // shade-card
    makeContainer('shade-card', () => {
        const d = document.createElement('div');
        d.style.cssText = 'background:#fff;border-radius:10px;box-shadow:0 6px 18px rgba(15,23,42,.06);padding:18px';
        return d;
    });

    // shade-list
    makeContainer('shade-list', () => {
        const ul = document.createElement('ul');
        ul.style.cssText = 'list-style:none;margin:0;padding:0';
        return ul;
    });

    // shade-label
    makeContainer('shade-label', () => {
        const lbl = document.createElement('label');
        lbl.style.cssText = 'display:block;font-size:13px;color:#374151;margin-bottom:6px';
        return lbl;
    });

    // shade-button
    makeContainer('shade-button', function (host) {
        const btn = document.createElement('button');
        btn.style.cssText = 'padding:8px 12px;border-radius:6px;background:#111827;color:#fff;border:none;cursor:pointer';
        // Copy type/disabled attrs
        ['type', 'disabled'].forEach(a => { if (host.hasAttribute(a)) btn.setAttribute(a, host.getAttribute(a)); });
        // Forward click to host so React onClick fires
        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            host.dispatchEvent(new MouseEvent('click', { bubbles: true, cancelable: true, composed: true }));
        });
        return btn;
    });

    // shade-form: wraps children in a <form> and forwards submit
    makeContainer('shade-form', function (host) {
        const f = document.createElement('form');
        f.addEventListener('submit', (ev) => {
            ev.preventDefault();
            host.dispatchEvent(new Event('submit', { bubbles: true, composed: true, cancelable: true }));
        });
        return f;
    });

    // shade-header: title + subtitle above slotted children
    class ShadeHeader extends HTMLElement {
        constructor() {
            super();
            const root = this.attachShadow({ mode: 'open' });
            const header = document.createElement('header');
            header.style.cssText = 'display:flex;align-items:center;justify-content:space-between;gap:12px;margin-bottom:16px';
            const meta = document.createElement('div');
            const h1 = document.createElement('h1');
            h1.style.cssText = 'margin:0;font-size:20px';
            h1.textContent = this.getAttribute('title') || '';
            meta.appendChild(h1);
            const sub = this.getAttribute('subtitle');
            if (sub) {
                    s.textContent = sub;
                s.style.cssText = 'color:#6b7280;font-size:13px';
                meta.appendChild(s);
            }
            header.appendChild(meta);
            const slot = document.createElement('slot');
            header.appendChild(slot);
            root.appendChild(header);
        }
    }
    customElements.define('shade-header', ShadeHeader);

    // --- Leaf elements: use Shadow DOM, reflect value/attrs, dispatch events ---
    function makeInput(tagName, type) {
        class C extends HTMLElement {
            #inner = null;
            constructor() {
                super();
                const root = this.attachShadow({ mode: 'open' });
                const el = document.createElement(type === 'textarea' ? 'textarea' : 'input');
                el.style.cssText = 'display:block;padding:10px;margin:6px 0 12px;width:100%;max-width:480px;border:1px solid #e6edf3;border-radius:6px;box-sizing:border-box';
                if (type && type !== 'textarea') el.type = type;
                this.#inner = el;
                // Reflect current attributes set before upgrade
                Array.from(this.attributes).forEach(a => {
                    if (a.name !== 'value') el.setAttribute(a.name, a.value);
                });
                if (this.hasAttribute('value')) el.value = this.getAttribute('value');
                // Value property mirrors inner element
                Object.defineProperty(this, 'value', {
                    get: () => el.value,
                    set: (v) => { el.value = v ?? ''; },
                    enumerable: true, configurable: true,
                });
                // Forward events with composed:true so React synthetic events fire on host
                ['input', 'change'].forEach(evt =>
                    el.addEventListener(evt, () =>
                        this.dispatchEvent(new Event(evt, { bubbles: true, composed: true }))
                    )
                );
                root.appendChild(el);
            }
            // React sets attributes for controlled inputs
            static get observedAttributes() { return ['value', 'type', 'placeholder', 'disabled', 'readonly']; }
            attributeChangedCallback(name, _old, next) {
                if (!this.#inner) return;
                if (name === 'value') { this.#inner.value = next ?? ''; }
                else if (next === null) { this.#inner.removeAttribute(name); }
                else { this.#inner.setAttribute(name, next); }
            }
        }
        customElements.define(tagName, C);
    }

    makeInput('shade-input');
    makeInput('shade-textarea', 'textarea');

})();

